const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const fromAddress = body.fromAddress || '';
const subject = body.subject || '';
const bodyText = (body.bodyText || '').substring(0, 2000);

if (!tenantId) {
  return [{ json: { valid: false, error: 'tenantId requis' } }];
}

return [{ json: { tenantId, fromAddress, subject, bodyText, valid: true } }];

const email = $('02. Valider').first().json;
const rulesRows = $input.all().map(i => i.json);

// Appliquer les règles statiques en priorité
for (const rule of rulesRows) {
  if (rule.type_rule !== 'static') continue;
  const conditions = typeof rule.conditions === 'string' ? JSON.parse(rule.conditions) : (rule.conditions || {});
  let match = true;

  if (conditions.from_contains && !email.fromAddress.toLowerCase().includes(conditions.from_contains.toLowerCase())) match = false;
  if (conditions.subject_contains && !email.subject.toLowerCase().includes(conditions.subject_contains.toLowerCase())) match = false;
  if (conditions.body_contains && !email.bodyText.toLowerCase().includes(conditions.body_contains.toLowerCase())) match = false;
  if (conditions.from_domain) {
    const domain = email.fromAddress.split('@')[1] || '';
    if (domain.toLowerCase() !== conditions.from_domain.toLowerCase()) match = false;
  }

  if (match) {
    const actionConfig = typeof rule.action_config === 'string' ? JSON.parse(rule.action_config) : (rule.action_config || {});
    return [{ json: {
      category: actionConfig.category || 'rule_match',
      priority: actionConfig.priority || 'normal',
      intent: actionConfig.intent || 'rule_based',
      confidence: 1.0,
      autoReplyEligible: rule.action_type === 'auto_reply',
      matchedRule: rule.id,
      matchedRuleName: rule.nom,
      source: 'static_rule'
    } }];
  }
}

// Pas de règle statique matchée : passer à la classification IA
return [{ json: {
  needsAI: true,
  tenantId: email.tenantId,
  fromAddress: email.fromAddress,
  subject: email.subject,
  bodyText: email.bodyText
} }];

const aiResponse = $input.first().json;
let parsed;
try {
  const text = aiResponse.message?.content || aiResponse.text || JSON.stringify(aiResponse);
  // Extraire le JSON même s'il est dans un bloc code
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  parsed = { category: 'autre', priority: 'normale', intent: 'classification_failed', confidence: 0.3, autoReplyEligible: false };
}

return [{ json: {
  data: {
    category: parsed.category || 'autre',
    priority: parsed.priority || 'normale',
    intent: parsed.intent || 'unknown',
    confidence: Math.min(1, Math.max(0, Number(parsed.confidence) || 0.5)),
    autoReplyEligible: parsed.autoReplyEligible === true,
    suggestedAction: parsed.suggestedAction || 'queue_human',
    source: 'ai_classification'
  }
} }];

// Résultat de règle statique — déjà formaté
const data = $('04. Appliquer règles statiques').first().json;
return [{ json: { data } }];
